function resolveYandexHelperCommand() {
  const envPath = String(process.env.FLOW_YANDEX_HELPER_PATH || '').trim()
  if (envPath && fs.existsSync(envPath)) return { file: envPath, args: [] }

  const helperRoot = path.join(__dirname, 'tools', 'flow-yandex-helper')
  const publishedExe = path.join(helperRoot, 'bin', 'Release', 'net8.0', 'win-x64', 'publish', 'FlowYandexMusicHelper.exe')
  const releaseDll = path.join(helperRoot, 'bin', 'Release', 'net8.0', 'FlowYandexMusicHelper.dll')
  const debugDll = path.join(helperRoot, 'bin', 'Debug', 'net8.0', 'FlowYandexMusicHelper.dll')
  if (fs.existsSync(publishedExe)) return { file: publishedExe, args: [] }
  if (fs.existsSync(releaseDll)) return { file: 'dotnet', args: [releaseDll] }
  if (fs.existsSync(debugDll)) return { file: 'dotnet', args: [debugDll] }

  const csproj = path.join(helperRoot, 'FlowYandexMusicHelper.csproj')
  if (process.env.FLOW_YANDEX_HELPER_RUN_SOURCE === '1' && fs.existsSync(csproj)) {
    return { file: 'dotnet', args: ['run', '--project', helperRoot, '--no-launch-profile', '--'] }
  }
  return null
}

function fetchYandexPlaylistWithHelper(link, token) {
  const cmd = resolveYandexHelperCommand()
  if (!cmd) return Promise.resolve(null)
  return new Promise((resolve, reject) => {
    execFile(
      cmd.file,
      [...cmd.args, '--playlist-url', link],
      {
        cwd: __dirname,
        env: { ...process.env, FLOW_YANDEX_TOKEN: token },
        timeout: 55000,
        maxBuffer: 24 * 1024 * 1024,
        windowsHide: true,
      },
      (err, stdout, stderr) => {
        const raw = String(stdout || '').trim()
        const jsonLine = raw.split(/\r?\n/).reverse().find((line) => line.trim().startsWith('{'))
        let parsed = null
        if (jsonLine) {
          try { parsed = JSON.parse(jsonLine) } catch (_) {}
        }
        if (err && !parsed) return reject(new Error(String(stderr || err.message || err)))
        if (!parsed?.ok) return reject(new Error(parsed?.error || String(stderr || 'Yandex helper failed')))
        const rows = Array.isArray(parsed?.playlist?.tracks) ? parsed.playlist.tracks : []
        const tracks = rows.map((t) => ({
          title: t?.title || null,
          artist: t?.artist || '—',
          duration: Number(t?.duration || 0) || null,
          original_id: t?.originalId || null,
          cover: t?.cover || null,
        })).filter((t) => t.title)
        if (!tracks.length) return reject(new Error('Yandex helper returned empty playlist'))
        resolve({
          ok: true,
          service: 'yandex',
          name: String(parsed?.playlist?.name || 'Yandex Playlist'),
          tracks,
        })
      },
    )
  })
}

async function fetchVkPlaylistFromFlowServer(serverBaseUrl, link, token = '') {
  let base = String(serverBaseUrl || '').trim()
  if (!base) return null
  if (!/^https?:\/\//i.test(base)) base = `http://${base}`
  base = base.replace(/\/+$/, '').replace(/\/health$/i, '')
  if (/^https:\/\/85\.239\.34\.229(?::8787)?$/i.test(base)) base = base.replace(/^https:/i, 'http:')
  const rsp = await axios.post(`${base}/vk/playlist`, {
    url: String(link || '').trim(),
    token: String(token || '').trim(),
  }, {
    timeout: 30000,
    maxBodyLength: 256 * 1024,
    validateStatus: () => true,
    headers: { 'Content-Type': 'application/json' },
  })
  const body = rsp?.data || {}
  if (!body?.ok) throw new Error(body?.error || `server status ${rsp?.status || 0}`)
  const tracks = Array.isArray(body.tracks)
    ? body.tracks.map((t) => ({
      title: t?.title || null,
      artist: t?.artist || '—',
      duration: Number(t?.duration || 0) || null,
      original_id: t?.original_id || t?.originalId || null,
    })).filter((t) => t.title)
    : []
  if (!tracks.length) throw new Error('server returned empty VK playlist')
  return {
    ok: true,
    service: 'vk',
    name: String(body.name || 'VK Playlist'),
    tracks,
    via: 'flow-vk-server',
  }
}

function extractYandexTrackOriginalId(track = {}, row = {}) {
  const rawId = track?.id != null ? track.id : (row?.trackId != null ? row.trackId : row?.id)
  const value = String(rawId ?? '').trim()
  if (!value) return null
  if (!value.includes(':')) return value
  const head = value.split(':')[0]?.trim()
  return head || value
}

/** Нормализует треклист альбома из ответа /albums/<id>/with-tracks */
function flattenYandexAlbumTracks(result = {}) {
  const out = []
  const push = (item) => {
    const t = item?.track || item
    if (!t?.title) return
    out.push({
      title: String(t.title || '').trim() || null,
      artist: Array.isArray(t.artists) ? t.artists.map((a) => a?.name).filter(Boolean).join(', ') : '—',
      duration: Number(t.durationMs || 0) > 0 ? Math.max(1, Math.floor(Number(t.durationMs) / 1000)) : null,
      original_id: extractYandexTrackOriginalId(t, item),
      cover: t.coverUri ? 'https://' + String(t.coverUri).replace('%%', '300x300') : null,
    })
  }
  const volumes = Array.isArray(result.volumes) ? result.volumes : []
  for (const vol of volumes) {
    if (Array.isArray(vol)) vol.forEach(push)
    else if (vol && typeof vol === 'object' && Array.isArray(vol.tracks)) vol.tracks.forEach(push)
  }
  if (!out.length && Array.isArray(result.tracks)) result.tracks.forEach(push)
  return out.filter((t) => t.title)
}

/** uid/login для путей /users/<id>/... (литерал «me» API не принимает). */
async function getYandexMusicAccountUid(ymHeaders) {
  const r = await httpsGetJson('api.music.yandex.net', '/account/settings', ymHeaders, 12000)
  const res = r?.body?.result
  if (!res || typeof res !== 'object') return null
  if (res.uid !== undefined && res.uid !== null) return String(res.uid).trim()
  if (typeof res.login === 'string' && res.login.trim()) return res.login.trim()
  return null
}

function mapYandexPlaylistTrackRowsToImport(tracks = []) {
  const out = []
  for (const row of tracks) {
    if (row && typeof row === 'object' && row.error) continue
    const t = row?.track || row
    if (!t?.title) continue
    out.push({
      title: t.title,
      artist: Array.isArray(t.artists) ? t.artists.map((a) => a?.name).filter(Boolean).join(', ') : '—',
      duration: Number(t.durationMs || 0) > 0 ? Math.max(1, Math.floor(Number(t.durationMs) / 1000)) : null,
      original_id: extractYandexTrackOriginalId(t, row),
      cover: t.coverUri ? 'https://' + String(t.coverUri).replace('%%', '300x300') : null,
    })
  }
  return out.filter((x) => x.title)
}

/** Полные объекты треков из ответа POST /tracks (массив в result). */
function mapYandexTrackObjectsToImport(tracks = []) {
  const out = []
  for (const t of tracks) {
    if (!t || typeof t !== 'object' || t.error) continue
    if (!t.title) continue
    out.push({
      title: t.title,
      artist: Array.isArray(t.artists) ? t.artists.map((a) => a?.name).filter(Boolean).join(', ') : '—',
      duration: Number(t.durationMs || 0) > 0 ? Math.max(1, Math.floor(Number(t.durationMs) / 1000)) : null,
      original_id: extractYandexTrackOriginalId(t, t),
      cover: t.coverUri ? 'https://' + String(t.coverUri).replace('%%', '300x300') : null,
    })
  }
  return out.filter((x) => x.title)
}

/**
 * Строки плейлиста без вложенного track.title часто содержат только id (часто «trackId:albumId»).
 * Собираем идентификаторы для POST /tracks как у yandex-music-api (MarshalX).
 */
function collectYandexPlaylistTrackIdsForBatch(tracks = []) {
  const out = []
  const seen = new Set()
  const add = (spec) => {
    const s = String(spec ?? '').trim()
    if (!s || seen.has(s)) return
    seen.add(s)
    out.push(s)
  }
  for (const row of tracks) {
    if (!row || typeof row !== 'object' || row.error) continue
    const nested = row.track
    if (nested && typeof nested === 'object' && nested.title) continue
    if (typeof row.id === 'string' && row.id.includes(':')) {
      add(row.id)
      continue
    }
    const tid = row.trackId != null ? row.trackId : row.id
    const aid = row.albumId != null ? row.albumId : (nested && nested.albumId != null ? nested.albumId : null)
    if (tid != null && aid != null) add(`${tid}:${aid}`)
    else if (tid != null) add(String(tid))
    else if (nested && nested.id != null) {
      const ntid = nested.id
      const said = nested.albumId != null ? nested.albumId
        : (Array.isArray(nested.albums) && nested.albums[0]?.id != null ? nested.albums[0].id : null)
      if (said != null) add(`${ntid}:${said}`)
      else add(String(ntid))
    }
  }
  return out
}

/** POST /tracks с track-ids[] (form), чанками — дозагрузка метаданных для lk.* и др. */
async function fetchYandexTracksByIdsForImport(ymHeaders, trackIds) {
  const ids = Array.isArray(trackIds) ? trackIds.filter(Boolean) : []
  if (!ids.length) return []
  const chunkSize = 150
  const merged = []
  for (let i = 0; i < ids.length; i += chunkSize) {
    const chunk = ids.slice(i, i + chunkSize)
    const form = new URLSearchParams()
    form.append('with-positions', 'true')
    for (const id of chunk) form.append('track-ids', String(id))
    let r = await httpsPostFormJson('api.music.yandex.net', '/tracks', form, ymHeaders, 35000)
    let list = Array.isArray(r?.body?.result) ? r.body.result : []
    if (!list.length) {
      r = await httpsPostFormJson('api.music.yandex.net', '/tracks/', form, ymHeaders, 35000)
      list = Array.isArray(r?.body?.result) ? r.body.result : []
    }
    const part = mapYandexTrackObjectsToImport(list)
    merged.push(...part)
  }
  return merged
}

function isYandexLikesPlaylistKind(kind) {
  return /^lk\./i.test(String(kind || '').trim())
}

/**
 * «Мне нравится» (kind lk.*): список треков в API — GET /users/:uid/likes/tracks (result.library.tracks),
 * а не /users/.../playlists/lk... (для OAuth там часто приходит пустой tracks).
 */
async function fetchYandexUserLikesTracksForImport(ymHeaders, uid) {
  const user = encodeURIComponent(String(uid || '').trim())
  if (!user) return { name: 'Мне нравится', tracksOut: [] }
  const paths = [
    `/users/${user}/likes/tracks?if-modified-since-revision=0`,
    `/users/${user}/likes/tracks`,
  ]
  let rows = []
  for (const p of paths) {
    const r = await httpsGetJson('api.music.yandex.net', p, ymHeaders, 40000)
    const res = r?.body?.result
    let lib = null
    if (res && typeof res === 'object') {
      if (res.library && typeof res.library === 'object') lib = res.library
      else if (Array.isArray(res.tracks)) lib = res
    }
    rows = Array.isArray(lib?.tracks) ? lib.tracks : []
    if (rows.length) break
  }
  if (!rows.length) return { name: 'Мне нравится', tracksOut: [] }
  const seen = new Set()
  const batchIds = []
  for (const row of rows) {
    if (!row || typeof row !== 'object') continue
    const id = row.id != null ? String(row.id).trim() : ''
    const aid = row.albumId != null ? String(row.albumId).trim() : ''
    const spec = id && aid ? `${id}:${aid}` : id
    if (!spec || seen.has(spec)) continue
    seen.add(spec)
    batchIds.push(spec)
  }
  const tracksOut = await fetchYandexTracksByIdsForImport(ymHeaders, batchIds)
  return { name: 'Мне нравится', tracksOut }
}

/**
 * Плейлисты вроде «Мне нравится» (kind lk.*) с короткой ссылки /playlists/lk…
 * часто приходят без вложенных track на обычном GET — нужен rich-tracks или POST /users/…/playlists.
 */
async function fetchYandexUserPlaylistForImport(ymHeaders, ownerId, kind) {
  const uid = String(ownerId || '').trim()
  const k = String(kind || '').trim()
  if (!uid || !k) return { pl: null, tracksOut: [] }

  const pathKind = encodeURIComponent(k)

  const load = async (pl) => ({
    pl: pl && typeof pl === 'object' ? pl : null,
    tracksOut: mapYandexPlaylistTrackRowsToImport(Array.isArray(pl?.tracks) ? pl.tracks : []),
  })

  let pl = null
  let tracksOut = []
  /** Не терять строки с track-id, если последний GET вернул пустой tracks. */
  let lastPlWithTrackRows = null
  const rememberRowsPl = (p) => {
    if (p && typeof p === 'object' && Array.isArray(p.tracks) && p.tracks.length) lastPlWithTrackRows = p
  }

  const rRich = await httpsGetJson(
    'api.music.yandex.net',
    `/users/${encodeURIComponent(uid)}/playlists/${pathKind}?rich-tracks=true`,
    ymHeaders,
    28000,
  )
  ;({ pl, tracksOut } = await load(rRich?.body?.result))
  rememberRowsPl(pl)
  if (tracksOut.length) return { pl, tracksOut }

  try {
    const postR = await httpsPostFormJson(
      'api.music.yandex.net',
      `/users/${encodeURIComponent(uid)}/playlists`,
      { kinds: k, mixed: 'false', 'rich-tracks': 'true' },
      ymHeaders,
      40000,
    )
    const raw = postR?.body?.result
    const first = Array.isArray(raw) ? raw[0] : raw
    ;({ pl, tracksOut } = await load(first))
    rememberRowsPl(pl)
    if (tracksOut.length) return { pl, tracksOut }
  } catch {}

  const rPlain = await httpsGetJson(
    'api.music.yandex.net',
    `/users/${encodeURIComponent(uid)}/playlists/${pathKind}`,
    ymHeaders,
    20000,
  )
  ;({ pl, tracksOut } = await load(rPlain?.body?.result))
  rememberRowsPl(pl)
  if (tracksOut.length) return { pl, tracksOut }

  const sourcePl = lastPlWithTrackRows || pl
  const rows = Array.isArray(sourcePl?.tracks) ? sourcePl.tracks : []
  if (rows.length) {
    const batchIds = collectYandexPlaylistTrackIdsForBatch(rows)
    if (batchIds.length) {
      const fromBatch = await fetchYandexTracksByIdsForImport(ymHeaders, batchIds)
      if (fromBatch.length) return { pl: sourcePl, tracksOut: fromBatch }
    }
  }
  return { pl: pl || sourcePl, tracksOut }
}

ipcMain.handle('import-playlist-link', async (e, { url, tokens = {} }) => {
  const link = String(url || '').trim()
  if (!link) return { ok: false, error: 'empty url' }

  const vkRef = parseVkPlaylistRef(link)
  if (vkRef) {
    const vkToken = String(tokens?.vk || '').trim()
    const serverBaseUrl = String(tokens?.serverBaseUrl || '').trim()
    let apiErr = null
    let serverErr = null
    let bridgeErr = null
    if (serverBaseUrl) {
      try {
        const fromServer = await fetchVkPlaylistFromFlowServer(serverBaseUrl, link, vkToken)
        if (fromServer?.tracks?.length) return fromServer
      } catch (err) {
        serverErr = err
      }
      return { ok: false, error: 'VK import server: ' + (serverErr?.message || 'server returned empty VK playlist') }
    }
    try {
      if (vkToken) {
        // Primary modern method for VK playlists.
        const pByIdObj = {
          owner_id: String(vkRef.ownerId),
          playlist_id: String(vkRef.albumId),
          access_token: vkToken,
        }
        if (vkRef.accessKey) pByIdObj.access_key = String(vkRef.accessKey)
        const byId = await vkInvokeKateMethod('audio.getPlaylistById', pByIdObj, 15000)
        if (!byId?.body?.error) {
          const r0 = Array.isArray(byId?.body?.response) ? byId.body.response[0] : (byId?.body?.response || {})
          const rawRows = Array.isArray(r0?.audios) ? r0.audios
            : (Array.isArray(r0?.list) ? r0.list : (Array.isArray(r0?.items) ? r0.items : []))
          const outById = rawRows.map((t) => ({
            title: t?.title || null,
            artist: t?.artist || (Array.isArray(t?.main_artists) ? t.main_artists.map((a) => a?.name).filter(Boolean).join(', ') : '—'),
            duration: Number(t?.duration || 0) || null,
            original_id: t?.owner_id && t?.id ? `${t.owner_id}_${t.id}` : (t?.id || null),
          })).filter((t) => t.title)
          if (outById.length) {
            const plName = String(r0?.title || 'VK Playlist')
            return { ok: true, service: 'vk', name: plName, tracks: outById }
          }
        }
        const paramsObj = {
          owner_id: String(vkRef.ownerId),
          album_id: String(vkRef.albumId),
          access_token: vkToken,
          count: '600',
        }
        if (vkRef.accessKey) paramsObj.access_key = String(vkRef.accessKey)
        const r = await vkInvokeKateMethod('audio.get', paramsObj, 15000)
        if (r?.body?.error) throw new Error(r.body.error.error_msg || 'VK API error')
        const items = vkAudioResponseItems(r.body) || []
        const out = items.map((t) => ({
          title: t?.title || null,
          artist: t?.artist || '—',
          duration: Number(t?.duration || 0) || null,
          original_id: t?.owner_id && t?.id ? `${t.owner_id}_${t.id}` : (t?.id || null),
        })).filter((t) => t.title)
        if (out.length) return { ok: true, service: 'vk', name: 'VK Playlist', tracks: out }
      }
    } catch (err) {
      apiErr = err
    }
    try {
      const openTracks = await fetchVkPlaylistMetaWithoutToken(link, vkRef)
      if (Array.isArray(openTracks) && openTracks.length) {
        return { ok: true, service: 'vk', name: 'VK Playlist', tracks: openTracks }
      }
    } catch {}
    try {
      const page = await httpGetTextUrl(link, { Referer: 'https://vk.com/' }, 17000)
      const parsed = extractVkPlaylistMetaFromHtml(page?.text || '')
      if (Array.isArray(parsed.tracks) && parsed.tracks.length) {
        return { ok: true, service: 'vk', name: parsed.name || 'VK Playlist', tracks: parsed.tracks }
      }
      const simple = extractVkSimplePairsFromHtml(page?.text || '', 120)
      if (simple.length) return { ok: true, service: 'vk', name: parsed.name || 'VK Playlist', tracks: simple }
    } catch {}
    try {
      const mobileUrl = `https://m.vk.com/audio?act=audio_playlist${vkRef.ownerId}_${vkRef.albumId}`
      const page = await httpGetTextUrl(mobileUrl, { Referer: 'https://vk.com/' }, 17000)
      const parsed = extractVkPlaylistMetaFromHtml(page?.text || '')
      if (Array.isArray(parsed.tracks) && parsed.tracks.length) {
        return { ok: true, service: 'vk', name: parsed.name || 'VK Playlist', tracks: parsed.tracks }
      }
      const simple = extractVkSimplePairsFromHtml(page?.text || '', 120)
      if (simple.length) return { ok: true, service: 'vk', name: parsed.name || 'VK Playlist', tracks: simple }
    } catch {}
    if (Boolean(tokens.allowVkSeleniumBridge)) {
      try {
        const bridge = await tryVkPlaylistBridge(link, 260)
        const out = Array.isArray(bridge?.tracks) ? bridge.tracks.map((t) => ({
          title: t?.title || null,
          artist: t?.artist || '—'
        })).filter((t) => t.title) : []
        if (out.length) return { ok: true, service: 'vk', name: 'VK Playlist', tracks: out }
        bridgeErr = bridge?.error || null
      } catch {}
    }
    if (bridgeErr) return { ok: false, error: 'VK import: ' + String(bridgeErr) }
    if (serverErr && apiErr) return { ok: false, error: 'VK import server: ' + (serverErr?.message || String(serverErr)) + ' | local: ' + (apiErr?.message || String(apiErr)) }
    if (apiErr) return { ok: false, error: 'VK import: ' + (apiErr?.message || String(apiErr)) + ' (html fallback failed)' }
    if (serverErr) return { ok: false, error: 'VK import server: ' + (serverErr?.message || String(serverErr)) }
    const chromeHint = !Boolean(tokens.allowVkSeleniumBridge)
      ? ' Если нужен импорт через отдельное окно Chrome (вход в VK), включи в настройках «Обход через Chrome (Selenium)».'
      : ''
    return { ok: false, error: 'VK import: playlist parse failed (try public playlist or valid VK token).' + chromeHint }
  }

  const spotifyId = parseSpotifyPlaylistId(link)
  if (spotifyId) {
    const spToken = String(tokens?.spotify || '').trim()
    if (!spToken) return { ok: false, error: 'Spotify token required' }
    const headers = { Authorization: `Bearer ${spToken}` }
    try {
      const meta = await httpsGetJsonUrl(`https://api.spotify.com/v1/playlists/${spotifyId}?fields=name`, headers, 12000)
      let next = `https://api.spotify.com/v1/playlists/${spotifyId}/tracks?limit=100`
      const out = []
      while (next && out.length < 600) {
        const r = await httpsGetJsonUrl(next, headers, 16000)
        const items = Array.isArray(r?.body?.items) ? r.body.items : []
        items.forEach((it) => {
          const t = it?.track
          if (!t?.name) return
          out.push({
            title: t.name,
            artist: Array.isArray(t.artists) ? t.artists.map((a) => a?.name).filter(Boolean).join(', ') : '—'
          })
        })
        next = String(r?.body?.next || '') || null
      }
      return { ok: true, service: 'spotify', name: String(meta?.body?.name || 'Spotify Playlist'), tracks: out }
    } catch (err) {
      return { ok: false, error: 'Spotify import: ' + (err?.message || String(err)) }
    }
  }

  const isYandexLink = /(^|\/\/)(music\.)?yandex\.[^/]+/i.test(link) || /(^|\/\/)yandex\.[^/]+/i.test(link)
  if (isYandexLink) {
    const ymToken = String(tokens?.yandex || '').trim()
    if (!ymToken) return { ok: false, error: 'Yandex token required' }
    let helperErr = null
    try {
      const fromHelper = await fetchYandexPlaylistWithHelper(link, ymToken)
      if (fromHelper?.tracks?.length) return { ...fromHelper, via: 'flow-yandex-helper' }
    } catch (err) {
      helperErr = err
    }
    const ymHeaders = {
      Authorization: `OAuth ${ymToken}`,
      'X-Yandex-Music-Client': 'WindowsPhone/3.20',
      'User-Agent': 'Windows 10',
    }
    const albumId = parseYandexAlbumId(link)
    if (albumId) {
      try {
        const r = await httpsGetJson(
          'api.music.yandex.net',
          `/albums/${encodeURIComponent(albumId)}/with-tracks`,
          ymHeaders,
          24000,
        )
        const result = r?.body?.result || {}
        const albumTitle = String(result?.title || `Yandex Альбом ${albumId}`)
        const out = flattenYandexAlbumTracks(result)
        if (out.length) return { ok: true, service: 'yandex', name: albumTitle, tracks: out }
        const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
        return { ok: false, error: 'Yandex import: в альбоме нет треков или API вернул пустой список' + helperMsg }
      } catch (err) {
        const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
        return { ok: false, error: 'Yandex import (альбом): ' + (err?.message || String(err)) + helperMsg }
      }
    }
    const yRef = parseYandexPlaylistRef(link)
    if (!yRef) {
      const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
      return { ok: false, error: 'Yandex import: не удалось распознать ссылку (нужен плейлист или album/ID)' + helperMsg }
    }
    try {
      let owner = String(yRef.user || '').trim()
      if (!owner || /^me$/i.test(owner)) {
        owner = await getYandexMusicAccountUid(ymHeaders)
        if (!owner) {
          const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
          return { ok: false, error: 'Yandex import: не удалось получить id аккаунта (account/settings). Проверь токен.' + helperMsg }
        }
      }
      if (isYandexLikesPlaylistKind(yRef.kind)) {
        const viaLikes = await fetchYandexUserLikesTracksForImport(ymHeaders, owner)
        if (viaLikes.tracksOut.length) {
          return { ok: true, service: 'yandex', name: viaLikes.name, tracks: viaLikes.tracksOut }
        }
      }
      const { pl, tracksOut } = await fetchYandexUserPlaylistForImport(ymHeaders, owner, yRef.kind)
      const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
      if (!tracksOut.length) {
        const rowN = Array.isArray(pl?.tracks) ? pl.tracks.length : 0
        const isLk = isYandexLikesPlaylistKind(yRef.kind)
        const msg = isLk && !rowN
          ? 'Yandex import: «Мне нравится» пусто в API (likes/tracks и плейлист lk не вернули треков). Если в браузере лайки есть — проверь права токена или пересоздай OAuth.'
          : !rowN
            ? 'Yandex import: в плейлисте не найдено треков (пустой список у API). Убедись, что ссылка и OAuth-токен относятся к одному аккаунту Яндекс Музыки.'
            : 'Yandex import: API вернул позиции плейлиста, но не удалось получить названия треков (попробуй обновить приложение или другую ссылку на плейлист).'
        return { ok: false, error: msg + helperMsg }
      }
      return { ok: true, service: 'yandex', name: String(pl?.title || 'Yandex Playlist'), tracks: tracksOut }
    } catch (err) {
      const helperMsg = helperErr ? ` | helper: ${helperErr?.message || String(helperErr)}` : ''
      return { ok: false, error: 'Yandex import: ' + (err?.message || String(err)) + helperMsg }
    }
  }

  return { ok: false, error: 'Unsupported playlist URL (Spotify / VK / Яндекс: плейлист или ссылка music.yandex.../album/<id>)' }
})

let _audiusHostCache = { host: null, ts: 0 }
async function getAudiusHost(force = false) {
  const now = Date.now()
  if (!force && _audiusHostCache.host && now - _audiusHostCache.ts < 10 * 60 * 1000) {
    return _audiusHostCache.host
  }
  const r = await httpsGetJsonUrl('https://api.audius.co/')
  const hosts = Array.isArray(r?.body?.data) ? r.body.data.filter(Boolean) : []
  if (!hosts.length) throw new Error('Audius discovery unavailable')
  const host = String(hosts[Math.floor(Math.random() * hosts.length)]).replace(/\/+$/, '')
  _audiusHostCache = { host, ts: now }
  return host
}

ipcMain.handle('audius-search', async (e, { q }) => {
  const query = String(q || '').trim()
  if (!query) return []
  let host = null
  try {
    host = await getAudiusHost(false)
    const p = `/v1/tracks/search?query=${encodeURIComponent(query)}&limit=20&app_name=flow`
    const r = await httpsGetJsonUrl(`${host}${p}`, {}, 12000)
    const items = Array.isArray(r?.body?.data) ? r.body.data : []
    return items.map((t) => {
      const id = String(t?.id || '')
      const cover = t?.artwork?.['480x480'] || t?.artwork?.['1000x1000'] || t?.artwork?.['150x150'] || null
      const stream = id ? `${host}/v1/tracks/${encodeURIComponent(id)}/stream?app_name=flow` : null
      return {
        title: t?.title || 'Без названия',
        artist: t?.user?.name || '—',
        url: stream,
        cover,
        bg: 'linear-gradient(135deg,#2dd4bf,#0ea5e9)',
        source: 'audius',
        id: id || `${t?.title || ''}:${t?.user?.name || ''}`
      }
    }).filter((t) => t.url)
  } catch (err) {
    // Retry once with refreshed discovery host.
    try {
      host = await getAudiusHost(true)
      const p = `/v1/tracks/search?query=${encodeURIComponent(query)}&limit=20&app_name=flow`
      const r = await httpsGetJsonUrl(`${host}${p}`, {}, 12000)
      const items = Array.isArray(r?.body?.data) ? r.body.data : []
      return items.map((t) => {
        const id = String(t?.id || '')
        const cover = t?.artwork?.['480x480'] || t?.artwork?.['1000x1000'] || t?.artwork?.['150x150'] || null
        const stream = id ? `${host}/v1/tracks/${encodeURIComponent(id)}/stream?app_name=flow` : null
        return {
          title: t?.title || 'Без названия',
          artist: t?.user?.name || '—',
          url: stream,
          cover,
          bg: 'linear-gradient(135deg,#2dd4bf,#0ea5e9)',
          source: 'audius',
          id: id || `${t?.title || ''}:${t?.user?.name || ''}`
        }
      }).filter((t) => t.url)
    } catch (e2) {
      throw new Error('Audius: ' + (e2?.message || err?.message || String(err)))
    }
  }
})

